function DB.GetAll(instanceID)
  local id = tonumber(instanceID or 0)
  if not id or id == 0 then return nil end
  return DB.entries[id]
end

function DB.Resolve(instanceID, faction)
  local entries = DB.GetAll(instanceID)
  if not entries or not entries[1] then return nil end
  if #entries == 1 then return entries[1] end
  local wantFaction = tonumber(faction)
  if wantFaction == 0 or wantFaction == 1 then
    for _, entry in ipairs(entries) do
      if entry.faction == wantFaction then return entry end
    end
  end
  for _, entry in ipairs(entries) do
    if entry.faction == -1 then return entry end
  end
  return entries[1]
end
